// @ts-ignore
const images = require.context("../../assets", false, /\.(png|jpe?g|gif|svg)$/);
function getImagesDateToPathMap() {
    return images.keys().reduce((map, key) => {
        const fileName = key.replace("./", "").replace(/\.(jpe?g)|png/, "");
        map[fileName] = images(key);
        return map;
    }, {});
}
export const imagesDateToPathMap = getImagesDateToPathMap();
